import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.next();

        // Security measure: Limit input length to avoid buffer overflow
        byte[] buffer = new byte[10];
        int length = Math.min(userInput.length(), buffer.length);
        Arrays.fill(buffer, (byte) 0); // Fill buffer with zeroes before copying
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, length);

        System.out.println("User input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
